using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

TrainAndSaveModel(dataPath, modelPath);

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with JSON body");

app.MapPost("/predict", (ChurnInput input, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        input.Age,
        input.Income,
        input.Region,
        input.PurchaseHistory,
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
    });
});

app.Run();

static void TrainAndSaveModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    IDataView data = mlContext.Data.LoadFromTextFile<ChurnInput>(
        dataPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    // Map "Yes"/"No" label to boolean, one-hot encode Region, combine features
    var pipeline = mlContext.Transforms.CustomMapping<ChurnInput, ChurnLabel>(
            (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
            contractName: "ChurnLabelMapping")
        .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region)))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnInput.Age),
            nameof(ChurnInput.Income),
            nameof(ChurnInput.PurchaseHistory),
            "RegionEncoded"))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

    var model = pipeline.Fit(split.TrainSet);

    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
}

public class ChurnLabel
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

